mapper.select:
/* adm-master-equipment-sql-oracle.xml  selectEquipmentCount */
SELECT COUNT(1)
FROM TADMIN_MST_EQ A
WHERE 1 = 1

	AND #{SEARCH_CONDITION}



	AND APKEY = #{apkey}


	AND EQKEY = #{eqkey}


	AND PRTYPE = #{prtype}

/* adm-master-equipment-sql-oracle.xml selectEquipment */ SELECT '0' AS CHK , A.APKEY , B.APNM , A.EQKEY , A.EQNM , A.EQTYPE , A.IPADDR , A.PRTYPE , A.DLVRYCORP , A.CLOSDATE , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY FROM TADMIN_MST_EQ A LEFT OUTER JOIN TADMIN_MST_AP B ON B.APKEY = A.APKEY WHERE 1 = 1
AND #{SEARCH_CONDITION}
AND A.APKEY = #{apkey}
AND A.EQKEY = #{eqkey}
AND A.PRTYPE = #{prtype}
ORDER BY A.UPDATEDATE DESC

mapper.insert:
/* adm-master-equipment-sql-oracle.xml  insertEquipment */
INSERT INTO TADMIN_MST_EQ(
	  APKEY
	, EQKEY
	, EQTYPE
	, IPADDR
	, EQNM
	, PRTYPE
	, DLVRYCORP
	, CLOSDATE
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
) VALUES (
	  #{apkey}
	, #{eqkey}
	, #{eqtype}
	, #{ipaddr}
	, #{eqnm}
	, #{prtype}
	, #{dlvrycorp}
	, #{closdate}
	, #{sysdate}
	, #{surkey}
	, #{sysdate}
	, #{surkey}
)

mapper.update:
/* adm-master-equipment-sql-oracle.xml  updateEquipment */
UPDATE TADMIN_MST_EQ
SET
	EQTYPE = #{eqtype}
  , IPADDR = #{ipaddr}
  , EQNM = #{eqnm}
  , DLVRYCORP = #{dlvrycorp}
  , CLOSDATE = #{closdate}
  ,UPDATEDATE = #{sysdate}
  ,UPDATEURKEY = #{surkey}
WHERE APKEY = #{apkey}
AND EQKEY = #{eqkey}
AND PRTYPE = #{prtype}

mapper.delete:
/* adm-master-equipment-sql-oracle.xml  deleteEquipment */
DELETE
FROM TADMIN_MST_EQ
WHERE APKEY = #{apkey}
AND EQKEY = #{eqkey}
AND PRTYPE = #{prtype}

